/**
 * @param {number} n Number of nodes
 * @param {number[][]} edges Array of [u, v, w]
 * @param {number} source Starting node
 * @param {number} target Destination node
 * @param {number} k Maximum allowed heavy edges
 * @return {number} Minimum threshold, or -1
 */
function solve(n, edges, source, target, k) {

    if (source === target) {
        return 0;
    }

    // Preprocess edges into an adjacency list structure for easy lookup
    // Adj[u] = list of {v, w}
    const adj = Array(n).fill(0).map(() => []);
    for (const [u, v, w] of edges) {
        adj[u].push({ node: v, weight: w });
        adj[v].push({ node: u, weight: w });
    }

    /**
     * Checks if a path exists from source to target using at most K heavy edges,
     * given the threshold T.
     * @param {number} T The threshold value.
     * @returns {boolean} True if such a path exists, false otherwise.
     */
    const canReach = (T) => {
        // D[u][c] is a boolean indicating if node u is reachable using exactly c heavy edges.
        // Size N x (K+1)
        const reachable = Array(n).fill(0).map(() => Array(k + 1).fill(false));

        // Queue for BFS: stores [node, heavy_count]
        const queue = [];

        // Initialize BFS
        reachable[source][0] = true;
        queue.push([source, 0]);

        let head = 0;
        while (head < queue.length) {
            const [u, c] = queue[head++];

            if (u === target) {
                // We found a path to target within the constraint, 
                // but we must continue BFS to ensure we explore all reachable states 
                // in case we need to find the absolute minimum threshold, 
                // but for this function's purpose, reaching target is enough.
                // Since BFS explores layer by layer (in terms of total edges), 
                // and we only care about existence, we can potentially return true early
                // if we are certain the current path is valid, but let's let BFS finish 
                // or just check the condition at the end for simplicity.
            }

            for (const edge of adj[u]) {
                const v = edge.node;
                const W = edge.weight;

                // Determine if the edge is heavy or light based on T
                const isHeavy = W > T ? 1 : 0;
                const cNew = c + isHeavy;

                if (cNew <= k && !reachable[v][cNew]) {
                    reachable[v][cNew] = true;
                    queue.push([v, cNew]);
                }
            }
        }

        // Check if the target was reached with any heavy edge count <= k
        for (let c = 0; c <= k; c++) {
            if (reachable[target][c]) {
                return true;
            }
        }
        return false;
    };

    // Binary Search for the minimum threshold T

    // The possible thresholds range from 0 up to max weight + 1.
    // Max weight is 10^9. We search in [0, 10^9 + 1].
    let L = 0;
    let R = 1000000000 + 1; // Upper bound for weights + 1
    let minThreshold = -1;

    // First, check if any path exists even when all edges are light (T = 10^9 + 1)
    // If canReach(R-1) is false, no path exists.
    if (!canReach(R - 1)) {
        return -1;
    }

    // Binary Search
    while (L < R) {
        // Use Math.floor for safe integer division
        const M = Math.floor(L + (R - L) / 2);

        if (canReach(M)) {
            // M works, it might be the minimum. Record it and try smaller.
            minThreshold = M;
            R = M;
        } else {
            // M does not work. We must allow more edges to be light, so increase T.
            L = M + 1;
        }
    }

    return minThreshold;
}

