function solve(n, edges, source, target, k) {

    if (source === target) {
        return 0;
    }

    // Preprocess edges into an adjacency list structure for easy lookup
    // Adj[u] = list of {v, w}
    const adj = Array(n).fill(0).map(() => []);
    for (const [u, v, w] of edges) {
        adj[u].push({ node: v, weight: w });
        adj[v].push({ node: u, weight: w });
    }

    /**
     * Checks if a path exists from source to target using at most K heavy edges,
     * given the threshold T.
     * @param {number} T The threshold value.
     * @returns {boolean} True if such a path exists, false otherwise.
     */
