import java.util.ArrayList;
import java.util.ArrayDeque;
import java.util.List;
import java.util.Queue;

public class Solution {

    // Helper structure for representing edges in the adjacency list
    private static class Edge {
        long destination;
        long weight;

        public Edge(long destination, long weight) {
            this.destination = destination;
            this.weight = weight;
        }
    }

    /**
     * Checks if a path exists from source to target using at most K heavy edges,
     * given the threshold T.
     * Time Complexity: O(N * K + M * K) where M is edges.length
     */
    private static boolean canReach(long T, int n, List<Edge>[] adj, long source, long target, int k) {

        // reachable[u][c] is true if node u is reachable using exactly c heavy edges.
        // N and K are guaranteed <= 1000, so array indexing is safe.
        boolean[][] reachable = new boolean[n][k + 1];

        // Queue for BFS: stores [node_index, heavy_count]
        // node_index and heavy_count fit within standard int range.
        Queue<int[]> queue = new ArrayDeque<>();

        int startNode = (int) source;
        int targetNode = (int) target;

        reachable[startNode][0] = true;
        queue.offer(new int[]{startNode, 0});

        while (!queue.isEmpty()) {
            int[] current = queue.poll();
            int u = current[0];
            int c = current[1];

            if (u == targetNode) {
                // We found a path. Since we only care about existence for a fixed T, we can stop early.
                return true;
            }

            for (Edge edge : adj[u]) {
                int v = (int) edge.destination;
                long W = edge.weight;

                // Determine heavy count increment: Heavy if W > T
                int isHeavy = (W > T) ? 1 : 0;
                int cNew = c + isHeavy;

                if (cNew <= k && !reachable[v][cNew]) {
                    reachable[v][cNew] = true;
                    queue.offer(new int[]{v, cNew});
                }
            }
        }

        // If the queue empties without reaching the target within k heavy edges
        return false;
    }


    public static long solve(long n_long, long[][] edges, long source, long target, long k_long) {

        int n = (int) n_long;
        int k = (int) k_long;

        if (source == target) {
            return 0;
        }

        // 1. Build Adjacency List
        List<Edge>[] adj = new List[n];
        for (int i = 0; i < n; i++) {
            adj[i] = new ArrayList<>();
        }

        // Track maximum weight to set the search range R
        long maxWeight = 0;
        for (long[] edge : edges) {
            long u = edge[0];
            long v = edge[1];
            long w = edge[2];

            adj[(int)u].add(new Edge(v, w));
            adj[(int)v].add(new Edge(u, w));

            if (w > maxWeight) {
                maxWeight = w;
            }
        }

        // 2. Binary Search for the minimum threshold T

        // Search range: [L, R]. 
        // L=0 (minimum possible threshold).
        // R=maxWeight + 1. Any threshold T >= maxWeight ensures all edges are light (heavy count 0).
        long L = 0;
        long R = maxWeight + 1; 
        long minThreshold = -1;

        // Check if even T=maxWeight + 1 (all light) results in connectivity.
        // If it doesn't, no path exists regardless of threshold.
        if (!canReach(R, n, adj, source, target, k)) {
             // Note: Since R = maxWeight + 1, any edge W <= R, so all edges are light (0 heavy edges).
             // If this fails, no path exists at all.
            return -1;
        }

        // Binary Search loop
        while (L < R) {
            // Standard safe middle calculation
            long M = L + (R - L) / 2;

            if (canReach(M, n, adj, source, target, k)) {
                // M works: path exists. M is a candidate answer. Try smaller T.
                minThreshold = M;
                R = M;
            } else {
                // M does not work: path requires too many heavy edges. Must increase T.
                L = M + 1;
            }
        }

        // minThreshold holds the smallest T found.
        return minThreshold;
    }
}

