import java.util.ArrayList;
import java.util.LinkedList;
import java.util.List;
import java.util.Queue;

public class Solution {

    // Helper class/record for graph edges
    static class Edge {
        int node;
        long weight;
        Edge(int node, long weight) {
            this.node = node;
            this.weight = weight;
        }
    }

    public static long solve(long n, long[][] edges, long source, long target, long k) {
        if (source == target) {
            return 0;
        }

        // Use int internally for node IDs and counts since N, K <= 1000
        int N = (int) n;
        int K = (int) k;
        int S = (int) source;
        int Tgt = (int) target;

        // Build Adjacency List
        List<Edge>[] adj = new ArrayList[N];
        for (int i = 0; i < N; i++) {
            adj[i] = new ArrayList<>();
        }
        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            long w = edge[2];
            adj[u].add(new Edge(v, w));
            adj[v].add(new Edge(u, w));
        }

        /**
         * Checks if a path exists from source to target using at most K heavy edges,
         * given the threshold T.
         */
        java.util.function.LongPredicate canReach = (threshold) -> {
            // reachable[u][c] = true if node u is reachable using exactly c heavy edges
            // Size N x (K+1)
            boolean[][] reachable = new boolean[N][K + 1];

            // Queue stores {node, heavy_count}
            Queue<int[]> queue = new LinkedList<>();

            reachable[S][0] = true;
            queue.offer(new int[]{S, 0});

            while (!queue.isEmpty()) {
                int[] current = queue.poll();
                int u = current[0];
                int c = current[1];

                if (u == Tgt) {
                    return true; 
                }

                for (Edge edge : adj[u]) {
                    int v = edge.node;
                    long W = edge.weight;

                    // Heavy if W > threshold
                    int isHeavy = (W > threshold) ? 1 : 0;
                    int cNew = c + isHeavy;

                    if (cNew <= K && !reachable[v][cNew]) {
                        reachable[v][cNew] = true;
                        queue.offer(new int[]{v, cNew});
                    }
                }
            }
            return false;
        };

        // Binary Search for the minimum threshold T

        // Search range [L, R). Max weight is 10^9. R = 10^9 + 1.
        long L = 0;
        long R = 1000000000L + 1; 
        long minThreshold = -1;

        // Pre-check: If no path exists even when all edges are light (T = R-1), return -1.
        if (!canReach.test(R - 1)) {
            return -1;
        }

        // Binary Search
        while (L < R) {
            long M = L + (R - L) / 2; 

            if (canReach.test(M)) {
                // M works. Record it and try for a smaller threshold.
                minThreshold = M;
                R = M;
            } else {
                // M does not work. We must increase the threshold to make more edges light.
                L = M + 1;
            }
        }

        return minThreshold;
    }
}

